package router

import (
	"context"
	"fmt"
	"net/http"
	"sync"
	"time"

	"github.com/gin-gonic/gin"
	"golang.org/x/net/http2"
	"golang.org/x/net/http2/h2c"
	"k8s.io/klog/v2"
)

const (
	ReadTimeout     = 30 * time.Second
	IdleTimeout     = 90 * time.Second
	ShutdownTimeout = 10 * time.Second
	DefaultMaxConcurrent = 1000
)

type Config struct {
	Port                  string
	EnableTLS             bool
	TLSCert               string
	TLSKey                string
	MaxConcurrentRequests int
}

type Server struct {
	config          *Config
	router          *gin.Engine
	httpServer      *http.Server
	sessionManager  SessionManager
	jwtManager      *JWTManager
	semaphore       chan struct{}
	wg              sync.WaitGroup
}

func NewServer(config *Config) (*Server, error) {
	if config.MaxConcurrentRequests <= 0 {
		config.MaxConcurrentRequests = DefaultMaxConcurrent
	}

	if config.EnableTLS && (config.TLSCert == "" || config.TLSKey == "") {
		return nil, fmt.Errorf("TLS is enabled but cert/key not provided")
	}

	gin.SetMode(gin.ReleaseMode)
	r := gin.New()
	r.Use(gin.Logger())
	r.Use(gin.Recovery())

	jwtManager, err := NewJWTManager()
	if err != nil {
		return nil, fmt.Errorf("failed to create JWT manager: %w", err)
	}

	if err := jwtManager.TryStoreOrLoadJWTKeySecret(context.Background()); err != nil {
		return nil, fmt.Errorf("failed to initialize JWT keys: %w", err)
	}

	sessionManager, err := NewSessionManager()
	if err != nil {
		return nil, fmt.Errorf("failed to create session manager: %w", err)
	}

	s := &Server{
		config:         config,
		router:         r,
		sessionManager: sessionManager,
		jwtManager:     jwtManager,
		semaphore:      make(chan struct{}, config.MaxConcurrentRequests),
	}

	s.setupRoutes()

	h2s := &http2.Server{}
	handler := h2c.NewHandler(r, h2s)

	s.httpServer = &http.Server{
		Addr:         ":" + config.Port,
		Handler:      handler,
		ReadTimeout:  ReadTimeout,
		IdleTimeout:  IdleTimeout,
	}

	return s, nil
}

func (s *Server) setupRoutes() {
	s.router.GET("/health/live", s.handleHealthLive)
	s.router.GET("/health/ready", s.handleHealthReady)

	v1 := s.router.Group("/v1")
	v1.Use(s.concurrencyMiddleware())

	v1.GET("/namespaces/:namespace/agent-runtimes/:name/invocations/*path", s.handleInvoke)
	v1.POST("/namespaces/:namespace/agent-runtimes/:name/invocations/*path", s.handleInvoke)
	v1.GET("/namespaces/:namespace/code-interpreters/:name/invocations/*path", s.handleInvoke)
	v1.POST("/namespaces/:namespace/code-interpreters/:name/invocations/*path", s.handleInvoke)
}

func (s *Server) concurrencyMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		select {
		case s.semaphore <- struct{}{}:
			defer func() { <-s.semaphore }()
			c.Next()
		default:
			c.JSON(http.StatusTooManyRequests, gin.H{
				"error": "server overloaded, please try again later",
				"code":  "SERVER_OVERLOADED",
			})
			c.Abort()
		}
	}
}

func (s *Server) handleHealthLive(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "alive"})
}

func (s *Server) handleHealthReady(c *gin.Context) {
	if s.sessionManager == nil {
		c.JSON(http.StatusServiceUnavailable, gin.H{
			"status": "not ready",
			"error":  "session manager not available",
		})
		return
	}
	c.JSON(http.StatusOK, gin.H{"status": "ready"})
}

func (s *Server) Start(ctx context.Context) error {
	klog.Infof("Starting router server on port %s", s.config.Port)

	if s.config.EnableTLS {
		return s.httpServer.ListenAndServeTLS(s.config.TLSCert, s.config.TLSKey)
	}
	return s.httpServer.ListenAndServe()
}

func (s *Server) Shutdown(ctx context.Context) error {
	return s.httpServer.Shutdown(ctx)
}

package router

import (
	"net/http"
	"time"

	"github.com/gin-gonic/gin"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/common/types"
)

const SessionHeader = "x-agentcube-session-id"

func (s *Server) handleInvoke(c *gin.Context) {
	namespace := c.Param("namespace")
	name := c.Param("name")
	path := c.Param("path")

	var kind string
	if c.Request.URL.Path.Contains("/agent-runtimes/") {
		kind = types.AgentRuntimeKind
	} else if c.Request.URL.Path.Contains("/code-interpreters/") {
		kind = types.CodeInterpreterKind
	}

	sessionID := c.GetHeader(SessionHeader)

	sandbox, err := s.sessionManager.GetSandboxBySession(c.Request.Context(), sessionID, namespace, name, kind)
	if err != nil {
		klog.Warningf("Failed to get sandbox by session: %v", err)
		c.JSON(http.StatusNotFound, gin.H{"error": "session not found"})
		return
	}

	if err := s.sessionManager.UpdateLastActivity(c.Request.Context(), sandbox.SessionID, time.Now()); err != nil {
		klog.Warningf("Failed to update last activity: %v", err)
	}

	proxy := NewProxy(sandbox, s.jwtManager)
	proxy.ServeHTTP(c.Writer, c.Request, path)

	if err := s.sessionManager.UpdateLastActivity(c.Request.Context(), sandbox.SessionID, time.Now()); err != nil {
		klog.Warningf("Failed to update last activity after proxy: %v", err)
	}

	c.Writer.Header().Set(SessionHeader, sandbox.SessionID)
}

package main

import (
	"context"
	"flag"
	"os"
	"os/signal"
	"syscall"

	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/router"
)

func main() {
	var config router.Config
	flag.StringVar(&config.Port, "port", "8080", "Server port")
	flag.BoolVar(&config.EnableTLS, "enable-tls", false, "Enable TLS")
	flag.StringVar(&config.TLSCert, "tls-cert", "", "TLS certificate path")
	flag.StringVar(&config.TLSKey, "tls-key", "", "TLS key path")
	flag.IntVar(&config.MaxConcurrentRequests, "max-concurrent", 1000, "Maximum concurrent requests")
	flag.Parse()

	server, err := router.NewServer(&config)
	if err != nil {
		klog.Fatalf("Failed to create server: %v", err)
	}

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)

	go func() {
		if err := server.Start(ctx); err != nil {
			klog.Fatalf("Server error: %v", err)
		}
	}()

	<-sigCh
	klog.Info("Shutting down server...")

	shutdownCtx, shutdownCancel := context.WithTimeout(context.Background(), router.ShutdownTimeout)
	defer shutdownCancel()

	if err := server.Shutdown(shutdownCtx); err != nil {
		klog.Errorf("Server shutdown error: %v", err)
	}
}

package router

import (
	"bytes"
	"context"
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"fmt"
	"os"
	"strings"
	"time"

	"github.com/golang-jwt/jwt/v5"
	corev1 "k8s.io/api/core/v1"
	"k8s.io/apimachinery/pkg/api/errors"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/client-go/kubernetes"
	"k8s.io/client-go/rest"
	"k8s.io/klog/v2"
)

const (
	IdentitySecretName      = "picod-router-identity"
	PrivateKeyDataKey       = "private.pem"
	PublicKeyDataKey        = "public.pem"
	KeySize                 = 2048
)

type JWTManager struct {
	privateKey *rsa.PrivateKey
	publicKey  *rsa.PublicKey
	clientset  kubernetes.Interface
}

func NewJWTManager() (*JWTManager, error) {
	config, err := rest.InClusterConfig()
	if err != nil {
		klog.Info("Not running in cluster, JWT keys must be provided via environment")
		return &JWTManager{}, nil
	}

	clientset, err := kubernetes.NewForConfig(config)
	if err != nil {
		return nil, fmt.Errorf("failed to create kubernetes client: %w", err)
	}

	return &JWTManager{
		clientset: clientset,
	}, nil
}

func (jm *JWTManager) GenerateToken(claims map[string]interface{}) (string, error) {
	if jm.privateKey == nil {
		return "", fmt.Errorf("private key not loaded")
	}

	jwtClaims := jwt.MapClaims{}
	for k, v := range claims {
		jwtClaims[k] = v
	}
	jwtClaims["iat"] = time.Now().Unix()
	jwtClaims["exp"] = time.Now().Add(time.Hour).Unix()

	token := jwt.NewWithClaims(jwt.SigningMethodRS256, jwtClaims)
	return token.SignedString(jm.privateKey)
}

func (jm *JWTManager) ValidateToken(tokenString string) (*jwt.Token, error) {
	if jm.publicKey == nil {
		return nil, fmt.Errorf("public key not loaded")
	}

	return jwt.Parse(tokenString, func(token *jwt.Token) (interface{}, error) {
		if _, ok := token.Method.(*jwt.SigningMethodRSA); !ok {
			return nil, fmt.Errorf("unexpected signing method: %v", token.Header["alg"])
		}
		return jm.publicKey, nil
	}, jwt.WithExpirationRequired(), jwt.WithIssuedAt(), jwt.WithLeeway(time.Minute))
}

func (jm *JWTManager) TryStoreOrLoadJWTKeySecret(ctx context.Context) error {
	if jm.clientset == nil {
		return jm.loadKeysFromEnv()
	}

	namespace := os.Getenv("AGENTCUBE_NAMESPACE")
	if namespace == "" {
		namespace = "default"
	}

	secret, err := jm.clientset.CoreV1().Secrets(namespace).Get(ctx, IdentitySecretName, metav1.GetOptions{})
	if err != nil {
		if errors.IsNotFound(err) {
			return jm.createKeySecret(ctx, namespace)
		}
		return fmt.Errorf("failed to get identity secret: %w", err)
	}

	return jm.loadKeysFromSecret(secret)
}

func (jm *JWTManager) createKeySecret(ctx context.Context, namespace string) error {
	privateKey, err := rsa.GenerateKey(rand.Reader, KeySize)
	if err != nil {
		return fmt.Errorf("failed to generate private key: %w", err)
	}

	privateKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "RSA PRIVATE KEY",
		Bytes: x509.MarshalPKCS1PrivateKey(privateKey),
	})

	publicKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "RSA PUBLIC KEY",
		Bytes: x509.MarshalPKCS1PublicKey(&privateKey.PublicKey),
	})

	secret := &corev1.Secret{
		ObjectMeta: metav1.ObjectMeta{
			Name:      IdentitySecretName,
			Namespace: namespace,
		},
		Type: corev1.SecretTypeOpaque,
		Data: map[string][]byte{
			PrivateKeyDataKey: privateKeyPEM,
			PublicKeyDataKey:  publicKeyPEM,
		},
	}

	_, err = jm.clientset.CoreV1().Secrets(namespace).Create(ctx, secret, metav1.CreateOptions{})
	if err != nil {
		return fmt.Errorf("failed to create identity secret: %w", err)
	}

	jm.privateKey = privateKey
	jm.publicKey = &privateKey.PublicKey
	klog.Infof("Created identity secret %s in namespace %s", IdentitySecretName, namespace)
	return nil
}

func (jm *JWTManager) loadKeysFromSecret(secret *corev1.Secret) error {
	privateKeyPEM, ok := secret.Data[PrivateKeyDataKey]
	if !ok {
		return fmt.Errorf("private key not found in secret")
	}

	publicKeyPEM, ok := secret.Data[PublicKeyDataKey]
	if !ok {
		return fmt.Errorf("public key not found in secret")
	}

	privateKeyBlock, _ := pem.Decode(privateKeyPEM)
	if privateKeyBlock == nil {
		return fmt.Errorf("failed to decode private key PEM")
	}

	privateKey, err := x509.ParsePKCS1PrivateKey(privateKeyBlock.Bytes)
	if err != nil {
		return fmt.Errorf("failed to parse private key: %w", err)
	}

	publicKeyBlock, _ := pem.Decode(publicKeyPEM)
	if publicKeyBlock == nil {
		return fmt.Errorf("failed to decode public key PEM")
	}

	publicKey, err := x509.ParsePKCS1PublicKey(publicKeyBlock.Bytes)
	if err != nil {
		return fmt.Errorf("failed to parse public key: %w", err)
	}

	jm.privateKey = privateKey
	jm.publicKey = publicKey
	klog.Info("Loaded JWT keys from secret")
	return nil
}

func (jm *JWTManager) loadKeysFromEnv() error {
	privateKeyPEM := os.Getenv("PICOD_AUTH_PRIVATE_KEY")
	publicKeyPEM := os.Getenv("PICOD_AUTH_PUBLIC_KEY")

	if privateKeyPEM == "" || publicKeyPEM == "" {
		return fmt.Errorf("PICOD_AUTH_PRIVATE_KEY and PICOD_AUTH_PUBLIC_KEY must be set when not running in cluster")
	}

	privateKeyBlock, _ := pem.Decode([]byte(privateKeyPEM))
	if privateKeyBlock == nil {
		return fmt.Errorf("failed to decode private key PEM from env")
	}

	privateKey, err := x509.ParsePKCS1PrivateKey(privateKeyBlock.Bytes)
	if err != nil {
		return fmt.Errorf("failed to parse private key: %w", err)
	}

	publicKeyBlock, _ := pem.Decode([]byte(publicKeyPEM))
	if publicKeyBlock == nil {
		return fmt.Errorf("failed to decode public key PEM from env")
	}

	publicKey, err := x509.ParsePKCS1PublicKey(publicKeyBlock.Bytes)
	if err != nil {
		return fmt.Errorf("failed to parse public key: %w", err)
	}

	jm.privateKey = privateKey
	jm.publicKey = publicKey
	klog.Info("Loaded JWT keys from environment")
	return nil
}

func (jm *JWTManager) GetPublicKey() *rsa.PublicKey {
	return jm.publicKey
}

package router

import (
	"crypto/rsa"
	"fmt"
	"net/http"
	"net/http/httputil"
	"net/url"
	"strings"
	"time"

	"github.com/volcano-sh/agentcube/pkg/common/types"
	"k8s.io/klog/v2"
)

type Proxy struct {
	sandbox   *types.SandboxInfo
	jwtManager *JWTManager
	transport *http.Transport
}

func NewProxy(sandbox *types.SandboxInfo, jwtManager *JWTManager) *Proxy {
	return &Proxy{
		sandbox:    sandbox,
		jwtManager: jwtManager,
		transport: &http.Transport{
			MaxIdleConns:        100,
			MaxIdleConnsPerHost: 10,
			IdleConnTimeout:     90 * time.Second,
		},
	}
}

func (p *Proxy) ServeHTTP(w http.ResponseWriter, r *http.Request, path string) {
	if len(p.sandbox.EntryPoints) == 0 {
		http.Error(w, `{"error":"no entry point found for sandbox"}`, http.StatusNotFound)
		return
	}

	entryPoint := p.findEntryPoint(path)
	if entryPoint == nil {
		entryPoint = &p.sandbox.EntryPoints[0]
	}

	targetURL, err := p.buildTargetURL(entryPoint)
	if err != nil {
		klog.Errorf("Failed to build target URL: %v", err)
		http.Error(w, `{"error":"failed to build target URL"}`, http.StatusInternalServerError)
		return
	}

	director := func(req *http.Request) {
		req.URL.Scheme = targetURL.Scheme
		req.URL.Host = targetURL.Host
		req.Host = targetURL.Host

		if path != "" {
			if !strings.HasPrefix(path, "/") {
				path = "/" + path
			}
			req.URL.Path = path
		}

		req.Header.Set("X-Forwarded-Host", r.Host)
		if r.TLS != nil {
			req.Header.Set("X-Forwarded-Proto", "https")
		} else {
			req.Header.Set("X-Forwarded-Proto", "http")
		}

		clientIP := r.RemoteAddr
		if idx := strings.LastIndex(clientIP, ":"); idx != -1 {
			clientIP = clientIP[:idx]
		}
		if prior := req.Header.Get("X-Forwarded-For"); prior != "" {
			clientIP = prior + ", " + clientIP
		}
		req.Header.Set("X-Forwarded-For", clientIP)

		if p.sandbox.Kind == types.SandboxKind || p.sandbox.Kind == types.SandboxClaimsKind {
			token, err := p.jwtManager.GenerateToken(map[string]interface{}{
				"session_id": p.sandbox.SessionID,
				"sandbox_id": p.sandbox.SandboxID,
			})
			if err != nil {
				klog.Errorf("Failed to generate JWT: %v", err)
				return
			}
			req.Header.Set("Authorization", "Bearer "+token)
		}
	}

	errorHandler := func(rw http.ResponseWriter, req *http.Request, err error) {
		klog.Errorf("Proxy error: %v", err)
		if strings.Contains(err.Error(), "connection refused") {
			http.Error(rw, `{"error":"sandbox unreachable"}`, http.StatusBadGateway)
		} else if strings.Contains(err.Error(), "timeout") {
			http.Error(rw, `{"error":"sandbox timeout"}`, http.StatusGatewayTimeout)
		} else {
			http.Error(rw, `{"error":"sandbox unreachable"}`, http.StatusBadGateway)
		}
	}

	proxy := &httputil.ReverseProxy{
		Director:       director,
		Transport:      p.transport,
		ErrorHandler:   errorHandler,
		ModifyResponse: p.modifyResponse,
	}

	proxy.ServeHTTP(w, r)
}

func (p *Proxy) findEntryPoint(path string) *types.SandboxEntryPoint {
	for _, ep := range p.sandbox.EntryPoints {
		if ep.Path != "" && strings.HasPrefix(path, ep.Path) {
			return &ep
		}
	}
	return nil
}

func (p *Proxy) buildTargetURL(entryPoint *types.SandboxEntryPoint) (*url.URL, error) {
	endpoint := entryPoint.Endpoint
	if entryPoint.Protocol != "" && !strings.Contains(endpoint, "://") {
		endpoint = strings.ToLower(string(entryPoint.Protocol)) + "://" + endpoint
	}

	return url.Parse(endpoint)
}

func (p *Proxy) modifyResponse(resp *http.Response) error {
	resp.Header.Set("x-agentcube-session-id", p.sandbox.SessionID)
	return nil
}

package router

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"net/http/httputil"
	"net/url"
	"os"
	"strings"
	"time"

	"github.com/volcano-sh/agentcube/pkg/common/types"
	"github.com/volcano-sh/agentcube/pkg/store"
	"k8s.io/klog/v2"
)

const (
	WorkloadManagerURLEnv = "WORKLOAD_MANAGER_URL"
	ServiceAccountTokenPath = "/var/run/secrets/kubernetes.io/serviceaccount/token"
)

type SessionManager interface {
	GetSandboxBySession(ctx context.Context, sessionID string, namespace string, name string, kind string) (*types.SandboxInfo, error)
	UpdateLastActivity(ctx context.Context, sessionID string, at time.Time) error
}

type sessionManager struct {
	store              store.Store
	workloadManagerURL string
	authToken          string
}

func NewSessionManager() (SessionManager, error) {
	workloadManagerURL := os.Getenv(WorkloadManagerURLEnv)
	if workloadManagerURL == "" {
		return nil, fmt.Errorf("WORKLOAD_MANAGER_URL environment variable is not set")
	}

	var authToken string
	if tokenBytes, err := os.ReadFile(ServiceAccountTokenPath); err == nil {
		authToken = strings.TrimSpace(string(tokenBytes))
	}

	s := store.Storage()
	if err := s.Ping(context.Background()); err != nil {
		return nil, fmt.Errorf("failed to ping store: %w", err)
	}

	return &sessionManager{
		store:              s,
		workloadManagerURL: workloadManagerURL,
		authToken:          authToken,
	}, nil
}

func (sm *sessionManager) GetSandboxBySession(ctx context.Context, sessionID string, namespace string, name string, kind string) (*types.SandboxInfo, error) {
	if sessionID != "" {
		sandbox, err := sm.store.GetSandboxBySessionID(ctx, sessionID)
		if err == nil {
			return sandbox, nil
		}
		if err != store.ErrNotFound {
			return nil, err
		}
	}

	return sm.createSession(ctx, namespace, name, kind)
}

func (sm *sessionManager) createSession(ctx context.Context, namespace string, name string, kind string) (*types.SandboxInfo, error) {
	reqBody := types.CreateSandboxRequest{
		Kind:      kind,
		Name:      name,
		Namespace: namespace,
	}

	jsonBody, err := json.Marshal(reqBody)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal request: %w", err)
	}

	endpoint := fmt.Sprintf("%s/v1/%s", sm.workloadManagerURL, getEndpointPath(kind))
	req, err := http.NewRequestWithContext(ctx, "POST", endpoint, bytes.NewBuffer(jsonBody))
	if err != nil {
		return nil, fmt.Errorf("failed to create request: %w", err)
	}

	req.Header.Set("Content-Type", "application/json")
	if sm.authToken != "" {
		req.Header.Set("Authorization", "Bearer "+sm.authToken)
	}

	client := &http.Client{Timeout: 30 * time.Second}
	resp, err := client.Do(req)
	if err != nil {
		return nil, fmt.Errorf("failed to call workload manager: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		body, _ := io.ReadAll(resp.Body)
		return nil, fmt.Errorf("workload manager returned %d: %s", resp.StatusCode, string(body))
	}

	var createResp types.CreateSandboxResponse
	if err := json.NewDecoder(resp.Body).Decode(&createResp); err != nil {
		return nil, fmt.Errorf("failed to decode response: %w", err)
	}

	if createResp.SessionID == "" {
		return nil, fmt.Errorf("session ID is empty in response")
	}

	sandbox := &types.SandboxInfo{
		Kind:             kind,
		SandboxID:        createResp.SandboxID,
		SandboxNamespace: namespace,
		Name:             createResp.SandboxName,
		EntryPoints:      createResp.EntryPoints,
		SessionID:        createResp.SessionID,
		CreatedAt:        time.Now(),
		Status:           "running",
	}

	return sandbox, nil
}

func (sm *sessionManager) UpdateLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	return sm.store.UpdateSessionLastActivity(ctx, sessionID, at)
}

func getEndpointPath(kind string) string {
	switch kind {
	case types.AgentRuntimeKind:
		return "agent-runtime"
	case types.CodeInterpreterKind:
		return "code-interpreter"
	default:
		return "agent-runtime"
	}
}

