package router

import (
	"crypto/rsa"
	"fmt"
	"net/http"
	"net/http/httputil"
	"net/url"
	"strings"
	"time"

	"github.com/volcano-sh/agentcube/pkg/common/types"
	"k8s.io/klog/v2"
)

type Proxy struct {
	sandbox    *types.SandboxInfo
	jwtManager *JWTManager
	transport  *http.Transport
}

func NewProxy(sandbox *types.SandboxInfo, jwtManager *JWTManager) *Proxy {
	return &Proxy{
		sandbox:    sandbox,
		jwtManager: jwtManager,
		transport: &http.Transport{
			MaxIdleConns:        100,
			MaxIdleConnsPerHost: 10,
			IdleConnTimeout:     90 * time.Second,
		},
	}
}

func (p *Proxy) ServeHTTP(w http.ResponseWriter, r *http.Request, path string) {
	if len(p.sandbox.EntryPoints) == 0 {
		http.Error(w, `{"error":"no entry point found for sandbox"}`, http.StatusNotFound)
		return
	}

	entryPoint := p.findEntryPoint(path)
	if entryPoint == nil {
		entryPoint = &p.sandbox.EntryPoints[0]
	}

	targetURL, err := p.buildTargetURL(entryPoint)
	if err != nil {
		klog.Errorf("Failed to build target URL: %v", err)
		http.Error(w, `{"error":"failed to build target URL"}`, http.StatusInternalServerError)
		return
	}

	director := func(req *http.Request) {
		req.URL.Scheme = targetURL.Scheme
		req.URL.Host = targetURL.Host
		req.Host = targetURL.Host

		if path != "" {
			if !strings.HasPrefix(path, "/") {
				path = "/" + path
			}
			req.URL.Path = path
		}

		req.Header.Set("X-Forwarded-Host", r.Host)
		if r.TLS != nil {
			req.Header.Set("X-Forwarded-Proto", "https")
		} else {
			req.Header.Set("X-Forwarded-Proto", "http")
		}

		clientIP := r.RemoteAddr
		if idx := strings.LastIndex(clientIP, ":"); idx != -1 {
			clientIP = clientIP[:idx]
		}
		if prior := req.Header.Get("X-Forwarded-For"); prior != "" {
			clientIP = prior + ", " + clientIP
		}
		req.Header.Set("X-Forwarded-For", clientIP)

		if p.sandbox.Kind == types.SandboxKind || p.sandbox.Kind == types.SandboxClaimsKind {
			token, err := p.jwtManager.GenerateToken(map[string]interface{}{
				"session_id": p.sandbox.SessionID,
				"sandbox_id": p.sandbox.SandboxID,
			})
			if err != nil {
				klog.Errorf("Failed to generate JWT: %v", err)
				return
			}
			req.Header.Set("Authorization", "Bearer "+token)
		}
	}

	errorHandler := func(rw http.ResponseWriter, req *http.Request, err error) {
		klog.Errorf("Proxy error: %v", err)
		if strings.Contains(err.Error(), "connection refused") {
			http.Error(rw, `{"error":"sandbox unreachable"}`, http.StatusBadGateway)
		} else if strings.Contains(err.Error(), "timeout") {
			http.Error(rw, `{"error":"sandbox timeout"}`, http.StatusGatewayTimeout)
		} else {
			http.Error(rw, `{"error":"sandbox unreachable"}`, http.StatusBadGateway)
		}
	}

	proxy := &httputil.ReverseProxy{
		Director:       director,
		Transport:      p.transport,
		ErrorHandler:   errorHandler,
		ModifyResponse: p.modifyResponse,
	}

	proxy.ServeHTTP(w, r)
}

func (p *Proxy) findEntryPoint(path string) *types.SandboxEntryPoint {
	for _, ep := range p.sandbox.EntryPoints {
		if ep.Path != "" && strings.HasPrefix(path, ep.Path) {
			return &ep
		}
	}
	return nil
}

func (p *Proxy) buildTargetURL(entryPoint *types.SandboxEntryPoint) (*url.URL, error) {
	endpoint := entryPoint.Endpoint
	if entryPoint.Protocol != "" && !strings.Contains(endpoint, "://") {
		endpoint = strings.ToLower(string(entryPoint.Protocol)) + "://" + endpoint
	}

	return url.Parse(endpoint)
}

func (p *Proxy) modifyResponse(resp *http.Response) error {
	resp.Header.Set("x-agentcube-session-id", p.sandbox.SessionID)
	return nil
}

