			clientIP = prior + ", " + clientIP
		}
		req.Header.Set("X-Forwarded-For", clientIP)

		if p.sandbox.Kind == types.SandboxKind || p.sandbox.Kind == types.SandboxClaimsKind {
			token, err := p.jwtManager.GenerateToken(map[string]interface{}{
				"session_id": p.sandbox.SessionID,
				"sandbox_id": p.sandbox.SandboxID,
			})
			if err != nil {
				klog.Errorf("Failed to generate JWT: %v", err)
				return
			}
			req.Header.Set("Authorization", "Bearer "+token)
		}
	}

	errorHandler := func(rw http.ResponseWriter, req *http.Request, err error) {
		klog.Errorf("Proxy error: %v", err)
		if strings.Contains(err.Error(), "connection refused") {
			http.Error(rw, `{"error":"sandbox unreachable"}`, http.StatusBadGateway)
		} else if strings.Contains(err.Error(), "timeout") {
			http.Error(rw, `{"error":"sandbox timeout"}`, http.StatusGatewayTimeout)
		} else {
			http.Error(rw, `{"error":"sandbox unreachable"}`, http.StatusBadGateway)
		}
	}

	proxy := &httputil.ReverseProxy{
		Director:       director,
		Transport:      p.transport,
		ErrorHandler:   errorHandler,
		ModifyResponse: p.modifyResponse,
	}

	proxy.ServeHTTP(w, r)
}

func (p *Proxy) findEntryPoint(path string) *types.SandboxEntryPoint {
	for _, ep := range p.sandbox.EntryPoints {
		if ep.Path != "" && strings.HasPrefix(path, ep.Path) {
			return &ep
		}
	}
	return nil
}

func (p *Proxy) buildTargetURL(entryPoint *types.SandboxEntryPoint) (*url.URL, error) {
	endpoint := entryPoint.Endpoint
	if entryPoint.Protocol != "" && !strings.Contains(endpoint, "://") {
		endpoint = strings.ToLower(string(entryPoint.Protocol)) + "://" + endpoint
	}

	return url.Parse(endpoint)
}

func (p *Proxy) modifyResponse(resp *http.Response) error {
	resp.Header.Set("x-agentcube-session-id", p.sandbox.SessionID)
	return nil
}

