	"k8s.io/klog/v2"
)

const (
	WorkloadManagerURLEnv   = "WORKLOAD_MANAGER_URL"
	ServiceAccountTokenPath = "/var/run/secrets/kubernetes.io/serviceaccount/token"
)

type SessionManager interface {
	GetSandboxBySession(ctx context.Context, sessionID string, namespace string, name string, kind string) (*types.SandboxInfo, error)
	UpdateLastActivity(ctx context.Context, sessionID string, at time.Time) error
}

type sessionManager struct {
	store              store.Store
	workloadManagerURL string
	authToken          string
}

func NewSessionManager() (SessionManager, error) {
	workloadManagerURL := os.Getenv(WorkloadManagerURLEnv)
	if workloadManagerURL == "" {
		return nil, fmt.Errorf("WORKLOAD_MANAGER_URL environment variable is not set")
	}

	var authToken string
	if tokenBytes, err := os.ReadFile(ServiceAccountTokenPath); err == nil {
		authToken = strings.TrimSpace(string(tokenBytes))
	}

	s := store.Storage()
	if err := s.Ping(context.Background()); err != nil {
		return nil, fmt.Errorf("failed to ping store: %w", err)
	}

	return &sessionManager{
		store:              s,
		workloadManagerURL: workloadManagerURL,
		authToken:          authToken,
	}, nil
}

func (sm *sessionManager) GetSandboxBySession(ctx context.Context, sessionID string, namespace string, name string, kind string) (*types.SandboxInfo, error) {
	if sessionID != "" {
		sandbox, err := sm.store.GetSandboxBySessionID(ctx, sessionID)
		if err == nil {
			return sandbox, nil
		}
		if err != store.ErrNotFound {
			return nil, err
		}
	}

	return sm.createSession(ctx, namespace, name, kind)
}

func (sm *sessionManager) createSession(ctx context.Context, namespace string, name string, kind string) (*types.SandboxInfo, error) {
	reqBody := types.CreateSandboxRequest{
		Kind:      kind,
		Name:      name,
		Namespace: namespace,
	}

	jsonBody, err := json.Marshal(reqBody)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal request: %w", err)
	}

	endpoint := fmt.Sprintf("%s/v1/%s", sm.workloadManagerURL, getEndpointPath(kind))
	req, err := http.NewRequestWithContext(ctx, "POST", endpoint, bytes.NewBuffer(jsonBody))
	if err != nil {
		return nil, fmt.Errorf("failed to create request: %w", err)
	}

	req.Header.Set("Content-Type", "application/json")
	if sm.authToken != "" {
		req.Header.Set("Authorization", "Bearer "+sm.authToken)
	}

	client := &http.Client{Timeout: 30 * time.Second}
	resp, err := client.Do(req)
	if err != nil {
		return nil, fmt.Errorf("failed to call workload manager: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		body, _ := io.ReadAll(resp.Body)
		return nil, fmt.Errorf("workload manager returned %d: %s", resp.StatusCode, string(body))
	}

	var createResp types.CreateSandboxResponse
	if err := json.NewDecoder(resp.Body).Decode(&createResp); err != nil {
		return nil, fmt.Errorf("failed to decode response: %w", err)
	}

	if createResp.SessionID == "" {
		return nil, fmt.Errorf("session ID is empty in response")
	}

	sandbox := &types.SandboxInfo{
		Kind:             kind,
		SandboxID:        createResp.SandboxID,
		SandboxNamespace: namespace,
		Name:             createResp.SandboxName,
		EntryPoints:      createResp.EntryPoints,
		SessionID:        createResp.SessionID,
		CreatedAt:        time.Now(),
		Status:           "running",
	}

	return sandbox, nil
}

func (sm *sessionManager) UpdateLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	return sm.store.UpdateSessionLastActivity(ctx, sessionID, at)
}

func getEndpointPath(kind string) string {
	switch kind {
	case types.AgentRuntimeKind:
		return "agent-runtime"
	case types.CodeInterpreterKind:
		return "code-interpreter"
	default:
		return "agent-runtime"
	}
}

