package router

import (
	"net/http"
	"net/http/httptest"
	"testing"

	"github.com/gin-gonic/gin"
	"github.com/stretchr/testify/assert"
)

func TestServerSetup(t *testing.T) {
	gin.SetMode(gin.TestMode)
	config := &Config{
		Port:                  "8080",
		MaxConcurrentRequests: 10,
	}

	server := &Server{
		config:    config,
		router:    gin.New(),
		semaphore: make(chan struct{}, config.MaxConcurrentRequests),
	}
	server.setupRoutes()

	tests := []struct {
		name       string
		method     string
		path       string
		wantStatus int
	}{
		{
			name:       "health live endpoint",
			method:     "GET",
			path:       "/health/live",
			wantStatus: http.StatusOK,
		},
		{
			name:       "health ready endpoint without session manager",
			method:     "GET",
			path:       "/health/ready",
			wantStatus: http.StatusServiceUnavailable,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			w := httptest.NewRecorder()
			req, _ := http.NewRequest(tt.method, tt.path, nil)
			server.router.ServeHTTP(w, req)
			assert.Equal(t, tt.wantStatus, w.Code)
		})
	}
}

func TestConcurrencyMiddleware(t *testing.T) {
	gin.SetMode(gin.TestMode)
	config := &Config{
		MaxConcurrentRequests: 1,
	}

	server := &Server{
		config:    config,
		semaphore: make(chan struct{}, config.MaxConcurrentRequests),
	}

	// Fill the semaphore
	server.semaphore <- struct{}{}

	r := gin.New()
	r.Use(server.concurrencyMiddleware())
	r.GET("/test", func(c *gin.Context) {
		c.JSON(http.StatusOK, gin.H{"status": "ok"})
	})

	w := httptest.NewRecorder()
	req, _ := http.NewRequest("GET", "/test", nil)
	r.ServeHTTP(w, req)

	assert.Equal(t, http.StatusTooManyRequests, w.Code)
	assert.Contains(t, w.Body.String(), "SERVER_OVERLOADED")
}

func TestDefaultMaxConcurrent(t *testing.T) {
	config := &Config{
		MaxConcurrentRequests: 0,
	}

	server, err := NewServer(config)
	if err != nil {
		t.Skip("Skipping test - store not available")
	}

	assert.Equal(t, DefaultMaxConcurrent, server.config.MaxConcurrentRequests)
}

func TestTLSErrors(t *testing.T) {
	config := &Config{
		EnableTLS: true,
		TLSCert:   "",
		TLSKey:    "",
	}

	_, err := NewServer(config)
	assert.Error(t, err)
	assert.Contains(t, err.Error(), "cert/key not provided")
}

package agentd

import (
	"context"
	"fmt"
	"time"

	"k8s.io/apimachinery/pkg/api/errors"
	"k8s.io/apimachinery/pkg/runtime"
	"k8s.io/client-go/rest"
	"k8s.io/klog/v2"
	sandboxv1alpha1 "sigs.k8s.io/agent-sandbox/api/v1alpha1"
	"sigs.k8s.io/controller-runtime/pkg/client"
	"sigs.k8s.io/controller-runtime/pkg/manager"
	"sigs.k8s.io/controller-runtime/pkg/reconcile"

	"github.com/volcano-sh/agentcube/pkg/workloadmanager"
)

const (
	SessionExpirationTimeout = 15 * time.Minute
)

type Reconciler struct {
	client client.Client
	scheme *runtime.Scheme
	mgr    manager.Manager
}

func NewReconciler() (*Reconciler, error) {
	config, err := rest.InClusterConfig()
	if err != nil {
		return nil, fmt.Errorf("failed to get in-cluster config: %w", err)
	}

	scheme := runtime.NewScheme()
	if err := sandboxv1alpha1.AddToScheme(scheme); err != nil {
		return nil, fmt.Errorf("failed to add sandbox scheme: %w", err)
	}

	mgr, err := manager.New(config, manager.Options{
		Scheme:                 scheme,
		MetricsBindAddress:     "0",
		HealthProbeBindAddress: "0",
	})
	if err != nil {
		return nil, fmt.Errorf("failed to create manager: %w", err)
	}

	return &Reconciler{
		client: mgr.GetClient(),
		scheme: scheme,
		mgr:    mgr,
	}, nil
}

func (r *Reconciler) Start() error {
	return r.mgr.Start(context.Background())
}

func (r *Reconciler) Reconcile(ctx context.Context, req reconcile.Request) (reconcile.Result, error) {
	sandbox := &sandboxv1alpha1.Sandbox{}
	if err := r.client.Get(ctx, req.NamespacedName, sandbox); err != nil {
		if errors.IsNotFound(err) {
			return reconcile.Result{}, nil
		}
		return reconcile.Result{}, err
	}

	lastActivityStr, ok := sandbox.Annotations[workloadmanager.LastActivityAnnotationKey]
	if !ok || lastActivityStr == "" {
		klog.V(4).Infof("Sandbox %s/%s has no last-activity-time annotation, skipping",
			req.Namespace, req.Name)
		return reconcile.Result{}, nil
	}

	lastActivity, err := time.Parse(time.RFC3339, lastActivityStr)
	if err != nil {
		klog.Warningf("Failed to parse last-activity-time for sandbox %s/%s: %v",
			req.Namespace, req.Name, err)
		return reconcile.Result{RequeueAfter: 30 * time.Second}, err
	}

	expirationTime := lastActivity.Add(SessionExpirationTimeout)
	if time.Now().After(expirationTime) {
		klog.Infof("Sandbox %s/%s has expired (last activity: %s), deleting",
			req.Namespace, req.Name, lastActivity.Format(time.RFC3339))

		if err := r.client.Delete(ctx, sandbox); err != nil {
			if errors.IsNotFound(err) {
				return reconcile.Result{}, nil
			}
			return reconcile.Result{}, fmt.Errorf("failed to delete sandbox: %w", err)
		}

		klog.Infof("Successfully deleted expired sandbox %s/%s", req.Namespace, req.Name)
		return reconcile.Result{}, nil
	}

	requeueAfter := time.Until(expirationTime)
	klog.V(4).Infof("Sandbox %s/%s not yet expired, requeueing in %v",
		req.Namespace, req.Name, requeueAfter)

	return reconcile.Result{RequeueAfter: requeueAfter}, nil
}

func (r *Reconciler) SetupWithManager(mgr manager.Manager) error {
	return nil
}

package agentd

import (
	"context"
	"testing"
	"time"

	"github.com/stretchr/testify/assert"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	sandboxv1alpha1 "sigs.k8s.io/agent-sandbox/api/v1alpha1"
	"sigs.k8s.io/controller-runtime/pkg/reconcile"

	"github.com/volcano-sh/agentcube/pkg/workloadmanager"
)

func TestReconciler_Reconcile_NoAnnotation(t *testing.T) {
	sandbox := &sandboxv1alpha1.Sandbox{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-sandbox",
			Namespace: "default",
		},
	}

	assert.Empty(t, sandbox.Annotations[workloadmanager.LastActivityAnnotationKey])
}

func TestReconciler_Reconcile_InvalidTimestamp(t *testing.T) {
	invalidTime := "invalid-timestamp"

	_, err := time.Parse(time.RFC3339, invalidTime)
	assert.Error(t, err)
}

func TestReconciler_Reconcile_Expired(t *testing.T) {
	oldTime := time.Now().Add(-20 * time.Minute).Format(time.RFC3339)
	expirationTime, _ := time.Parse(time.RFC3339, oldTime)
	expirationTime = expirationTime.Add(SessionExpirationTimeout)

	assert.True(t, time.Now().After(expirationTime))
}

func TestReconciler_Reconcile_NotExpired(t *testing.T) {
	recentTime := time.Now().Add(-5 * time.Minute).Format(time.RFC3339)
	lastActivity, _ := time.Parse(time.RFC3339, recentTime)
	expirationTime := lastActivity.Add(SessionExpirationTimeout)

	assert.False(t, time.Now().After(expirationTime))
	assert.True(t, time.Until(expirationTime) > 0)
}

func TestSessionExpirationTimeout(t *testing.T) {
	assert.Equal(t, 15*time.Minute, SessionExpirationTimeout)
}

package main

import (
	"os"

	"k8s.io/klog/v2"
	"sigs.k8s.io/controller-runtime/pkg/log/zap"

	"github.com/volcano-sh/agentcube/pkg/agentd"
)

func main() {
	log := zap.New()

	reconciler, err := agentd.NewReconciler()
	if err != nil {
		log.Error(err, "Failed to create reconciler")
		os.Exit(1)
	}

	if err := reconciler.Start(); err != nil {
		log.Error(err, "Failed to start reconciler")
		os.Exit(1)
	}
}
